1	//! Endpoints and generation-aware proc-number encoding.
2	//!
3	//! An `Endpoint` is the kernel's name for a process. It encodes both the
4	//! process-table slot (`ProcNr`) and a generation counter (`GenNr`) so that
5	//! a slot reuse after a process exit produces a distinct endpoint. This
6	//! catches stale-endpoint bugs in user-space code.
7	//!
8	//! Mirrors MINIX 3 `include/minix/type.h` (`typedef int endpoint_t`) and
9	//! `include/minix/endpoint.h` (the `_ENDPOINT(g, n)` / `_ENDPOINT_P(e)` /
10	//! `_ENDPOINT_G(e)` macros), with one deliberate ABI deviation: MINIX 4
11	//! uses sign-extension of the low `ENDPOINT_GEN_SHIFT` bits to recover
12	//! negative task slots, rather than MINIX 3's `MAX_NR_TASKS` offset-bias
13	//! trick. The consequence is that `make_endpoint(0, p) != p` for negative
14	//! `p` — use `boot_endpoint(p)` explicitly when constructing an endpoint
15	//! from a kernel-task `ProcNr` constant like `SYSTEM`.
16	
17	/// Kernel-assigned identifier for a process; encodes generation + proc_nr.
18	pub type Endpoint = i32;
19	
20	/// Index into the process table. Task slots are negative (`SYSTEM=-2`, …);
21	/// user-process slots are non-negative.
22	pub type ProcNr = i32;
23	
24	/// Generation counter — bumped when a process slot is reused.
25	pub type GenNr = i32;
26	
27	/// Width of the proc-number field within an endpoint, in bits. Generation
28	/// occupies the bits above this.
29	pub const ENDPOINT_GEN_SHIFT: i32 = 15;
30	
31	/// Mask covering the proc-number field of an endpoint.
32	pub const ENDPOINT_PROC_MASK: i32 = (1 << ENDPOINT_GEN_SHIFT) - 1;
33	
34	/// Highest positive proc-number representable at generation zero (one less
35	/// than the sign-bit boundary of the proc field). Sentinel endpoints live
36	/// just below this so they decode to gen 0 with proc-numbers well outside
37	/// any plausible `NR_PROCS`. Mirrors MINIX 3's `_ENDPOINT_SLOT_TOP`.
38	pub const ENDPOINT_SLOT_TOP: ProcNr = (1 << (ENDPOINT_GEN_SHIFT - 1)) - 1;
39	
40	/// Special endpoint matching any sender (used as the `src` argument to
41	/// `RECEIVE`). Always at generation zero.
42	pub const ANY: Endpoint = make_endpoint(0, ENDPOINT_SLOT_TOP);
43	
44	/// Special endpoint meaning "no process". Always at generation zero.
45	pub const NONE: Endpoint = make_endpoint(0, ENDPOINT_SLOT_TOP - 1);
46	
47	/// Special endpoint referring to the calling process itself. Always at
48	/// generation zero.
49	pub const SELF: Endpoint = make_endpoint(0, ENDPOINT_SLOT_TOP - 2);
50	
51	/// Encode `(generation, proc_nr)` into an endpoint.
52	pub const fn make_endpoint(g: GenNr, p: ProcNr) -> Endpoint {
53	    (g << ENDPOINT_GEN_SHIFT) | (p & ENDPOINT_PROC_MASK)
54	}
