57	/// the lower `ENDPOINT_GEN_SHIFT` bits so that task slots come back negative.
58	pub const fn endpoint_proc(e: Endpoint) -> ProcNr {
59	    let masked = e & ENDPOINT_PROC_MASK;
60	    let sign_bit = 1 << (ENDPOINT_GEN_SHIFT - 1);
61	    if masked & sign_bit != 0 {
62	        masked | !ENDPOINT_PROC_MASK
63	    } else {
64	        masked
65	    }
66	}
67	
68	/// Extract the generation counter from an endpoint.
69	pub const fn endpoint_gen(e: Endpoint) -> GenNr {
70	    e >> ENDPOINT_GEN_SHIFT
71	}
