    #[test]
    fn primitive_numbers_match_minix3() {
        // Values pinned by the MINIX 3 ABI — these must not drift.
        assert_eq!(SEND, 1);
        assert_eq!(RECEIVE, 2);
        assert_eq!(SENDREC, 3);
        assert_eq!(NOTIFY, 4);
        assert_eq!(SENDNB, 5);
