            None => f.write_str("-"),
        }
    }
}

struct RtsDecoder(u32);

impl fmt::Display for RtsDecoder {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let v = self.0;
        render_padded(f, |buf| {
            if v == 0 {
                return buf.write_str("RUN");
            }
            let mut first = true;
            let pairs: [(u32, &str); 12] = [
                (RTS_PROC_STOP, "STOP"),
                (RTS_SENDING, "SEND"),
                (RTS_RECEIVING, "RECV"),
                (RTS_SIGNALED, "SIGD"),
                (RTS_SIG_PENDING, "SIGP"),
                (RTS_NO_PRIV, "NOPRIV"),
                (RTS_NO_ENDPOINT, "NOEPT"),
                (RTS_VMINHIBIT, "VMINH"),
                (RTS_PAGEFAULT, "PGFLT"),
                (RTS_PREEMPTED, "PREEMPT"),
                (RTS_BOOTINHIBIT, "BOOTINH"),
                (RTS_SLOT_FREE, "FREE"),
            ];
            for (bit, name) in pairs {
                if v & bit != 0 {
                    if !first {
                        buf.write_char('|')?;
                    }
                    buf.write_str(name)?;
                    first = false;
                }
            }
            Ok(())
        })
    }
}

